tool.command:
@CMD_UNZIP_ZARR@
mkdir -p output_dir &&
## Determine the SpatialData directory name SDATA_DIR=\$(find . -maxdepth 1 -name "*.zarr" -type d | head -n 1) &&
## Run annotation sopa annotate #if $method.method_name == 'fluorescence' fluorescence "\${SDATA_DIR}" --marker-cell-dict '$method.marker_cell_dict' #else if $method.method_name == 'tangram' tangram "\${SDATA_DIR}" --reference '$method.reference_adata' #if str($method.marker_list) != '' --markers '$method.marker_list' #end if #if str($method.mode) != '' --mode '$method.mode' #end if #end if &&
## Move to output directory mv "\${SDATA_DIR}" output_dir/ &&
@CMD_ZIP_ZARR@
